#include <cstdio>
#include <algorithm>
using namespace std;

const int MAXN = 100005;
long long E[MAXN], S[MAXN];
long long dp[MAXN][2];
int N, K;

struct Deque {
    int q[MAXN], head, tail;
    Deque() { head = 0; tail = -1; }
    void push(int idx, long long val) {
        while (head <= tail && dp[q[tail]][0] - S[q[tail]] <= val) tail--;
        q[++tail] = idx;
    }
    int front() { return q[head]; }
    void pop_front() { head++; }
    bool empty() { return head > tail; }
};

int main() {
    scanf("%d %d", &N, &K);
    for (int i = 1; i <= N; i++) {
        scanf("%lld", &E[i]);
        S[i] = S[i-1] + E[i];
    }

    dp[0][0] = 0;
    dp[0][1] = -1e18;
    Deque dq;
    dq.push(0, dp[0][0] - S[0]);

    for (int i = 1; i <= N; i++) {
        dp[i][0] = max(dp[i-1][0], dp[i-1][1]);

        int left = i - K;
        while (!dq.empty() && dq.front() < left) dq.pop_front();
        int best_j = dq.front();
        dp[i][1] = dp[best_j][0] - S[best_j] + S[i];

        dq.push(i, dp[i][0] - S[i]);
    }

    printf("%lld\n", max(dp[N][0], dp[N][1]));
    return 0;
}
